    public Object nonce()
    {
        return Helpers.subtract(this.milliseconds(), Helpers.GetValue(this.options, "timeDifference"));
    }

    /**
     * @method
     * @name xt#fetchTime
     * @description fetches the current integer timestamp in milliseconds from the xt server
     * @see https://doc.xt.com/#market1serverInfo
     * @param {object} params extra parameters specific to the xt api endpoint
     * @returns {int} the current integer timestamp in milliseconds from the xt server
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTime(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicSpotGetTime(parameters)).join();
            //
            //     {
            //         "rc": 0,
            //         "mc": "SUCCESS",
            //         "ma": [],
            //         "result": {
            //             "serverTime": 1677823301643
            //         }
            //     }
            //
            Object data = this.safeValue(response, "result");
            return this.safeInteger(data, "serverTime");
        });

    }

    /**
     * @method
     * @name xt#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://doc.xt.com/#deposit_withdrawalsupportedCurrenciesGet
     * @param {object} params extra parameters specific to the xt api endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object promisesRaw = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.publicSpotGetWalletSupportCurrency(parameters), this.publicSpotGetCurrencies(parameters)));
            var chainsResponsecurrenciesResponseVariable = (Helpers.promiseAll(promisesRaw)).join();
            var chainsResponse = ((java.util.List<Object>) chainsResponsecurrenciesResponseVariable).get(0);
            var currenciesResponse = ((java.util.List<Object>) chainsResponsecurrenciesResponseVariable).get(1);
            //
            // currencies
            //
            //    {
            //        "time": "1686626116145",
            //        "version": "5dbbb2f2527c22b2b2e3b47187ef13d1",
            //        "currencies": [
            //            {
            //                "id": "2",
            //                "currency": "btc",
            //                "fullName": "Bitcoin",
            //                "logo": "https://a.static-global.com/1/currency/btc.png",
            //                "cmcLink": "https://coinmarketcap.com/currencies/bitcoin/",
            //                "weight": "99999",
            //                "maxPrecision": "10",
            //                "depositStatus": "1",
            //                "withdrawStatus": "1",
            //                "convertEnabled": "1",
            //                "transferEnabled": "1",
            //                "isChainExist": "1",
            //                "plates": [152]
            //            },
            //        ],
            //    }
            //
            //
            // chains
            //
            //     {
            //         "rc": 0,
            //         "mc": "SUCCESS",
            //         "ma": [],
            //         "result": [
            //             {
            //                 "currency": "btc",
            //                 "supportChains": [
            //                     {
            //                         "chain": "Bitcoin",
            //                         "depositEnabled": true,
            //                         "withdrawEnabled": true,
            //                         "withdrawFeeAmount": 0.0009,
            //                         "withdrawMinAmount": 0.0005,
            //                         "depositFeeRate": 0
            //                     },
            //                 ]
            //             },
            //         ]
            //     }
            //
            // note: individual network's full data is available on per-currency endpoint: https://www.xt.com/sapi/v4/balance/public/currency/11
            //
            Object chainsData = this.safeValue(chainsResponse, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object currenciesResult = this.safeValue(currenciesResponse, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object currenciesData = this.safeValue(currenciesResult, "currencies", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object chainsDataIndexed = this.indexBy(chainsData, "currency");
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currenciesData)); i++)
            {
                Object entry = Helpers.GetValue(currenciesData, i);
                Object currencyId = this.safeString(entry, "currency");
                Object code = this.safeCurrencyCode(currencyId);
                Object networkEntry = this.safeValue(chainsDataIndexed, currencyId, new java.util.HashMap<String, Object>() {{}});
                Object rawNetworks = this.safeValue(networkEntry, "supportChains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object networks = new java.util.HashMap<String, Object>() {{}};
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(rawNetworks)); j++)
                {
                    Object rawNetwork = Helpers.GetValue(rawNetworks, j);
                    Object networkId = this.safeString(rawNetwork, "chain");
                    Object networkCode = this.networkIdToCode(networkId, code);
                    Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
        put( "info", rawNetwork );
        put( "id", networkId );
        put( "network", networkCode );
        put( "name", null );
        put( "active", null );
        put( "fee", XtCore.this.safeNumber(rawNetwork, "withdrawFeeAmount") );
        put( "precision", null );
        put( "deposit", XtCore.this.safeBool(rawNetwork, "depositEnabled") );
        put( "withdraw", XtCore.this.safeBool(rawNetwork, "withdrawEnabled") );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "amount", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", XtCore.this.safeNumber(rawNetwork, "withdrawMinAmount") );
                put( "max", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
        }} );
    }});
                }
                Object typeRaw = this.safeString(entry, "type");
                Object type = null;
                if (Helpers.isTrue(Helpers.isEqual(typeRaw, "FT")))
                {
                    type = "crypto";
                } else
                {
                    type = "other";
                }
                final Object finalType = type;
                Helpers.addElementToObject(result, code, this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
        put( "info", entry );
        put( "id", currencyId );
        put( "code", code );
        put( "name", XtCore.this.safeString(entry, "fullName") );
        put( "active", null );
        put( "fee", null );
        put( "precision", XtCore.this.parseNumber(XtCore.this.parsePrecision(XtCore.this.safeString(entry, "maxPrecision"))) );
        put( "deposit", Helpers.isEqual(XtCore.this.safeString(entry, "depositStatus"), "1") );
        put( "withdraw", Helpers.isEqual(XtCore.this.safeString(entry, "withdrawStatus"), "1") );
        put( "networks", networks );
        put( "type", finalType );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "amount", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
        }} );
    }}));
            }
            return result;
        });

    }

    /**
     * @method
     * @name xt#fetchMarkets
     * @description retrieves data on all markets for xt
     * @see https://doc.xt.com/#market2symbol
     * @see https://doc.xt.com/#futures_quotesgetSymbols
     * @param {object} params extra parameters specific to the xt api endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.GetValue(this.options, "adjustForTimeDifference")))
            {
                (this.loadTimeDifference()).join();
            }
            Object promisesUnresolved = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.fetchSpotMarkets(parameters), this.fetchSwapAndFutureMarkets(parameters)));
            Object promises = (Helpers.promiseAll(promisesUnresolved)).join();
            Object spotMarkets = Helpers.GetValue(promises, 0);
            Object swapAndFutureMarkets = Helpers.GetValue(promises, 1);
            return this.arrayConcat(spotMarkets, swapAndFutureMarkets);
        });

    }

