    /**
     * @method
     * @name xt#fetchTickers
     * @description fetches price tickers for multiple markets, statistical calculations with the information calculated over the past 24 hours each market
     * @see https://doc.xt.com/#market10ticker24h
     * @see https://doc.xt.com/#futures_quotesgetAggTickers
     * @param {string} [symbols] unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} params extra parameters specific to the xt api endpoint
     * @returns {object} an array of [ticker structures]{@link https://docs.ccxt.com/en/latest/manual.html#ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                symbols = this.marketSymbols(symbols);
                market = this.market(Helpers.GetValue(symbols, 0));
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object type = null;
            Object subType = null;
            Object response = null;
            var typeparametersVariable = this.handleMarketTypeAndParams("fetchTickers", market, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            var subTypeparametersVariable = this.handleSubTypeAndParams("fetchTickers", market, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(subType, "inverse")))
            {
                response = (this.publicInverseGetFutureMarketV1PublicQAggTickers(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(subType, "linear"))) || Helpers.isTrue((Helpers.isEqual(type, "swap")))) || Helpers.isTrue((Helpers.isEqual(type, "future")))))
            {
                response = (this.publicLinearGetFutureMarketV1PublicQAggTickers(this.extend(request, parameters))).join();
            } else
            {
                response = (this.publicSpotGetTicker24h(this.extend(request, parameters))).join();
            }
            //
            // spot
            //
            //     {
            //         "rc": 0,
            //         "mc": "SUCCESS",
            //         "ma": [],
            //         "result": [
            //             {
            //                 "s": "btc_usdt",
            //                 "t": 1678172693931,
            //                 "cv": "34.00",
            //                 "cr": "0.0015",
            //                 "o": "22398.05",
            //                 "l": "22323.72",
            //                 "h": "22600.50",
            //                 "c": "22432.05",
            //                 "q": "7962.256931",
            //                 "v": "178675209.47416856"
            //             }
            //         ]
            //     }
            //
            // swap and future
            //
            //     {
            //         "returnCode": 0,
            //         "msgInfo": "success",
            //         "error": null,
            //         "result": [
            //             {
            //                 "t": 1680738775108,
            //                 "s": "badger_usdt",
            //                 "c": "2.7176",
            //                 "h": "2.7917",
            //                 "l": "2.6818",
            //                 "a": "88332",
            //                 "v": "242286.3520",
            //                 "o": "2.7422",
            //                 "r": "-0.0089",
            //                 "i": "2.7155",
            //                 "m": "2.7161",
            //                 "bp": "2.7152",
            //                 "ap": "2.7176"
            //             },
            //         ]
            //     }
            //
            Object tickers = this.safeValue(response, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(tickers)); i++)
            {
                Object ticker = this.parseTicker(Helpers.GetValue(tickers, i), market);
                Object symbol = Helpers.GetValue(ticker, "symbol");
                Helpers.addElementToObject(result, symbol, ticker);
            }
            return this.filterByArray(result, "symbol", symbols);
        });

    }

