    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // spot: fetchTicker, fetchTickers
        //
        //     {
        //         "s": "btc_usdt",
        //         "t": 1678172693931,
        //         "cv": "34.00",
        //         "cr": "0.0015",
        //         "o": "22398.05",
        //         "l": "22323.72",
        //         "h": "22600.50",
        //         "c": "22432.05",
        //         "q": "7962.256931",
        //         "v": "178675209.47416856"
        //     }
        //
        // swap and future: fetchTicker, fetchTickers
        //
        //     {
        //         "t": 1678172848572,
        //         "s": "btc_usdt",
        //         "c": "22415.5",
        //         "h": "22590.0",
        //         "l": "22310.0",
        //         "a": "623654031",
        //         "v": "1399166074.31675",
        //         "o": "22381.5",
        //         "r": "0.0015",
        //         "i": "22424.5",
        //         "m": "22416.5",
        //         "bp": "22415",
        //         "ap": "22415.5"
        //     }
        //
        // fetchBidsAsks
        //
        //     {
        //         "s": "kas_usdt",
        //         "t": 1679539891853,
        //         "ap": "0.016298",
        //         "aq": "5119.09",
        //         "bp": "0.016290",
        //         "bq": "135.37"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(ticker, "s");
        Object marketType = ((Helpers.isTrue((!Helpers.isEqual(market, null))))) ? Helpers.GetValue(market, "type") : null;
        Object hasSpotKeys = Helpers.isTrue((Helpers.inOp(ticker, "cv"))) || Helpers.isTrue((Helpers.inOp(ticker, "aq")));
        if (Helpers.isTrue(Helpers.isEqual(marketType, null)))
        {
            marketType = ((Helpers.isTrue(hasSpotKeys))) ? "spot" : "contract";
        }
        market = this.safeMarket(marketId, market, "_", marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(ticker, "t");
        Object percentage = this.safeString2(ticker, "cr", "r");
        if (Helpers.isTrue(!Helpers.isEqual(percentage, null)))
        {
            percentage = Precise.stringMul(percentage, "100");
        }
        final Object finalPercentage = percentage;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", XtCore.this.iso8601(timestamp) );
            put( "high", XtCore.this.safeNumber(ticker, "h") );
            put( "low", XtCore.this.safeNumber(ticker, "l") );
            put( "bid", XtCore.this.safeNumber(ticker, "bp") );
            put( "bidVolume", XtCore.this.safeNumber(ticker, "bq") );
            put( "ask", XtCore.this.safeNumber(ticker, "ap") );
            put( "askVolume", XtCore.this.safeNumber(ticker, "aq") );
            put( "vwap", null );
            put( "open", XtCore.this.safeString(ticker, "o") );
            put( "close", XtCore.this.safeString(ticker, "c") );
            put( "last", XtCore.this.safeString(ticker, "c") );
            put( "previousClose", null );
            put( "change", XtCore.this.safeNumber(ticker, "cv") );
            put( "percentage", XtCore.this.parseNumber(finalPercentage) );
            put( "average", null );
            put( "baseVolume", XtCore.this.safeNumber(ticker, "a") );
            put( "quoteVolume", XtCore.this.safeNumber(ticker, "v") );
            put( "info", ticker );
        }}, market);
    }

