    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // spot: fetchTrades
        //
        //     {
        //         "i": 203530723141917063,
        //         "t": 1678227505815,
        //         "p": "22038.81",
        //         "q": "0.000978",
        //         "v": "21.55395618",
        //         "b": true
        //     }
        //
        // spot: watchTrades
        //
        //    {
        //        s: 'btc_usdt',
        //        i: '228825383103928709',
        //        t: 1684258222702,
        //        p: '27003.65',
        //        q: '0.000796',
        //        b: true
        //    }
        //
        // spot: watchMyTrades
        //
        //    {
        //        "s": "btc_usdt",                // symbol
        //        "t": 1656043204763,             // time
        //        "i": "6316559590087251233",     // tradeId
        //        "oi": "6216559590087220004",    // orderId
        //        "p": "30000",                   // trade price
        //        "q": "3",                       // qty quantity
        //        "v": "90000"                    // volume trade amount
        //    }
        //
        // swap and future: fetchTrades
        //
        //     {
        //         "t": 1678227683897,
        //         "s": "btc_usdt",
        //         "p": "22031",
        //         "a": "1067",
        //         "m": "BID"
        //     }
        //
        // spot: fetchMyTrades
        //
        //     {
        //         "symbol": "btc_usdt",
        //         "tradeId": "206906233569974658",
        //         "orderId": "206906233178463488",
        //         "orderSide": "SELL",
        //         "orderType": "MARKET",
        //         "bizType": "SPOT",
        //         "time": 1679032290215,
        //         "price": "25703.46",
        //         "quantity": "0.000099",
        //         "quoteQty": "2.54464254",
        //         "baseCurrency": "btc",
        //         "quoteCurrency": "usdt",
        //         "fee": "0.00508929",
        //         "feeCurrency": "usdt",
        //         "takerMaker": "TAKER"
        //     }
        //
        // swap and future: fetchMyTrades
        //
        //     {
        //         "orderId": "207260566170987200",
        //         "execId": "207260566790603265",
        //         "symbol": "btc_usdt",
        //         "quantity": "13",
        //         "price": "27368",
        //         "fee": "0.02134704",
        //         "feeCoin": "usdt",
        //         "timestamp": 1679116769838,
        //         "takerMaker": "TAKER"
        //     }
        //
        // contract watchMyTrades
        //
        //    {
        //        "symbol": 'btc_usdt',
        //        "orderSide": 'SELL',
        //        "positionSide": 'LONG',
        //        "orderId": '231485367663419328',
        //        "price": '27152.7',
        //        "quantity": '33',
        //        "marginUnfrozen": '2.85318000',
        //        "timestamp": 1684892412565
        //    }
        //
        // watchMyTrades (ws, swap)
        //
        //    {
        //        'fee': '0.04080840',
        //        'isMaker': False,
        //        'marginUnfrozen': '0.75711984',
        //        'orderId': '376172779053188416',
        //        'orderSide': 'BUY',
        //        'positionSide': 'LONG',
        //        'price': '3400.70',
        //        'quantity': '2',
        //        'symbol': 'eth_usdt',
        //        'timestamp': 1719388579622
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString2(trade, "s", "symbol");
        Object marketType = ((Helpers.isTrue((!Helpers.isEqual(market, null))))) ? Helpers.GetValue(market, "type") : null;
        Object hasSpotKeys = Helpers.isTrue(Helpers.isTrue((Helpers.inOp(trade, "b"))) || Helpers.isTrue((Helpers.inOp(trade, "bizType")))) || Helpers.isTrue((Helpers.inOp(trade, "oi")));
        if (Helpers.isTrue(Helpers.isEqual(marketType, null)))
        {
            marketType = ((Helpers.isTrue(hasSpotKeys))) ? "spot" : "contract";
        }
        market = this.safeMarket(marketId, market, "_", marketType);
        Object side = null;
        Object takerOrMaker = null;
        Object isBuyerMaker = this.safeBool(trade, "b");
        if (Helpers.isTrue(!Helpers.isEqual(isBuyerMaker, null)))
        {
            side = ((Helpers.isTrue(isBuyerMaker))) ? "sell" : "buy";
            takerOrMaker = "taker"; // public trades always taker
        } else
        {
            Object takerMaker = this.safeStringLower(trade, "takerMaker");
            if (Helpers.isTrue(!Helpers.isEqual(takerMaker, null)))
            {
                takerOrMaker = takerMaker;
            } else
            {
                Object isMaker = this.safeBool(trade, "isMaker");
                if (Helpers.isTrue(!Helpers.isEqual(isMaker, null)))
                {
                    takerOrMaker = ((Helpers.isTrue(isMaker))) ? "maker" : "taker";
                }
            }
            Object orderSide = this.safeStringLower(trade, "orderSide");
            if (Helpers.isTrue(!Helpers.isEqual(orderSide, null)))
            {
                side = orderSide;
            } else
            {
                Object bidOrAsk = this.safeString(trade, "m");
                if (Helpers.isTrue(!Helpers.isEqual(bidOrAsk, null)))
                {
                    side = ((Helpers.isTrue((Helpers.isEqual(bidOrAsk, "BID"))))) ? "buy" : "sell";
                }
            }
        }
        Object timestamp = this.safeIntegerN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("t", "time", "timestamp")));
        Object quantity = this.safeString2(trade, "q", "quantity");
        Object amount = null;
        if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
        {
            amount = quantity;
        } else
        {
            if (Helpers.isTrue(Helpers.isEqual(quantity, null)))
            {
                amount = Precise.stringMul(this.safeString(trade, "a"), this.numberToString(Helpers.GetValue(market, "contractSize")));
            } else
            {
                amount = Precise.stringMul(quantity, this.numberToString(Helpers.GetValue(market, "contractSize")));
            }
        }
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalAmount = amount;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", XtCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("i", "tradeId", "execId"))) );
            put( "timestamp", timestamp );
            put( "datetime", XtCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "order", XtCore.this.safeString2(trade, "orderId", "oi") );
            put( "type", XtCore.this.safeStringLower(trade, "orderType") );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", XtCore.this.safeString2(trade, "p", "price") );
            put( "amount", finalAmount );
            put( "cost", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", XtCore.this.safeCurrencyCode(XtCore.this.safeString2(trade, "feeCurrency", "feeCoin")) );
                put( "cost", XtCore.this.safeString(trade, "fee") );
            }} );
        }}, market);
    }

