    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // spot: createOrder
        //
        //     {
        //         "orderId": "204371980095156544"
        //     }
        //
        // spot: cancelOrder
        //
        //     {
        //         "cancelId": "208322474307982720"
        //     }
        //
        // swap and future: createOrder, cancelOrder, editOrder
        //
        //     {
        //         "returnCode": 0,
        //         "msgInfo": "success",
        //         "error": null,
        //         "result": "206410760006650176"
        //     }
        //
        // spot: fetchOrder, fetchOrders, fetchOpenOrders, fetchClosedOrders, fetchCanceledOrders, fetchOrdersByStatus
        //
        //     {
        //         "symbol": "btc_usdt",
        //         "orderId": "207505997850909952",
        //         "clientOrderId": null,
        //         "baseCurrency": "btc",
        //         "quoteCurrency": "usdt",
        //         "side": "BUY",
        //         "type": "LIMIT",
        //         "timeInForce": "GTC",
        //         "price": "20000.00",
        //         "origQty": "0.001000",
        //         "origQuoteQty": "20.00",
        //         "executedQty": "0.000000",
        //         "leavingQty": "0.001000",
        //         "tradeBase": "0.000000",
        //         "tradeQuote": "0.00",
        //         "avgPrice": null,
        //         "fee": null,
        //         "feeCurrency": null,
        //         "closed": false,
        //         "state": "NEW",
        //         "time": 1679175285162,
        //         "updatedTime": 1679175285255
        //     }
        //
        // swap and future: fetchOrder, fetchOrders, fetchOpenOrders, fetchClosedOrders, fetchCanceledOrders, fetchOrdersByStatus
        //
        //     {
        //         "orderId": "207519546930995456",
        //         "clientOrderId": null,
        //         "symbol": "btc_usdt",
        //         "orderType": "LIMIT",
        //         "orderSide": "BUY",
        //         "positionSide": "LONG",
        //         "timeInForce": "GTC",
        //         "closePosition": false,
        //         "price": "20000",
        //         "origQty": "100",
        //         "avgPrice": "0",
        //         "executedQty": "0",
        //         "marginFrozen": "4.12",
        //         "remark": null,
        //         "triggerProfitPrice": null,
        //         "triggerStopPrice": null,
        //         "sourceId": null,
        //         "sourceType": "DEFAULT",
        //         "forceClose": false,
        //         "closeProfit": null,
        //         "state": "CANCELED",
        //         "createdTime": 1679178515689,
        //         "updatedTime": 1679180096172
        //     }
        //
        // trigger: fetchOrder, fetchOrders, fetchOpenOrders, fetchClosedOrders, fetchCanceledOrders, fetchOrdersByStatus
        //
        //     {
        //         "entrustId": "216300248132756992",
        //         "symbol": "btc_usdt",
        //         "entrustType": "STOP",
        //         "orderSide": "SELL",
        //         "positionSide": "SHORT",
        //         "timeInForce": "GTC",
        //         "closePosition": null,
        //         "price": "20000",
        //         "origQty": "1",
        //         "stopPrice": "19000",
        //         "triggerPriceType": "LATEST_PRICE",
        //         "state": "NOT_TRIGGERED",
        //         "marketOrderLevel": null,
        //         "createdTime": 1681271998064,
        //         "updatedTime": 1681271998064,
        //         "ordinary": false
        //     }
        //
        // stop-loss and take-profit: fetchOrder, fetchOpenOrders, fetchClosedOrders, fetchCanceledOrders, fetchOrdersByStatus
        //
        //     {
        //         "profitId": "216306213226230400",
        //         "symbol": "btc_usdt",
        //         "positionSide": "LONG",
        //         "origQty": "1",
        //         "triggerPriceType": "LATEST_PRICE",
        //         "triggerProfitPrice": null,
        //         "triggerStopPrice": "20000",
        //         "entryPrice": null,
        //         "positionSize": null,
        //         "isolatedMargin": null,
        //         "executedQty": null,
        //         "avgPrice": null,
        //         "positionType": "ISOLATED",
        //         "state": "NOT_TRIGGERED",
        //         "createdTime": 1681273420039
        //     }
        //
        // spot editOrder
        //
        //     {
        //         "orderId": "484203027161892224",
        //         "modifyId": "484203544105344000",
        //         "clientModifyId": null
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "symbol");
        Object marketType = ((Helpers.isTrue(Helpers.isTrue((Helpers.inOp(order, "result"))) || Helpers.isTrue((Helpers.inOp(order, "positionSide")))))) ? "contract" : "spot";
        market = this.safeMarket(marketId, market, null, marketType);
        Object symbol = this.safeSymbol(marketId, market, null, marketType);
        Object timestamp = this.safeInteger2(order, "time", "createdTime");
        Object quantity = this.safeNumber(order, "origQty");
        Object amount = ((Helpers.isTrue((Helpers.isEqual(marketType, "spot"))))) ? quantity : Precise.stringMul(this.numberToString(quantity), this.numberToString(Helpers.GetValue(market, "contractSize")));
        Object filledQuantity = this.safeNumber(order, "executedQty");
        Object filled = ((Helpers.isTrue((Helpers.isEqual(marketType, "spot"))))) ? filledQuantity : Precise.stringMul(this.numberToString(filledQuantity), this.numberToString(Helpers.GetValue(market, "contractSize")));
        Object lastUpdatedTimestamp = this.safeInteger(order, "updatedTime");
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", XtCore.this.safeStringN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("orderId", "result", "cancelId", "entrustId", "profitId"))) );
            put( "clientOrderId", XtCore.this.safeString2(order, "clientOrderId", "clientModifyId") );
            put( "timestamp", timestamp );
            put( "datetime", XtCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", lastUpdatedTimestamp );
            put( "lastUpdateTimestamp", lastUpdatedTimestamp );
            put( "symbol", symbol );
            put( "type", XtCore.this.safeStringLower2(order, "type", "orderType") );
            put( "timeInForce", XtCore.this.safeString(order, "timeInForce") );
            put( "postOnly", null );
            put( "side", XtCore.this.safeStringLower2(order, "side", "orderSide") );
            put( "price", XtCore.this.safeNumber(order, "price") );
            put( "triggerPrice", XtCore.this.safeNumber(order, "stopPrice") );
            put( "stopLoss", XtCore.this.safeNumber(order, "triggerStopPrice") );
            put( "takeProfit", XtCore.this.safeNumber(order, "triggerProfitPrice") );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", XtCore.this.safeNumber(order, "leavingQty") );
            put( "cost", null );
            put( "average", XtCore.this.safeNumber(order, "avgPrice") );
            put( "status", XtCore.this.parseOrderStatus(XtCore.this.safeString(order, "state")) );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", XtCore.this.safeCurrencyCode(XtCore.this.safeString(order, "feeCurrency")) );
                put( "cost", XtCore.this.safeNumber(order, "fee") );
            }} );
            put( "trades", null );
        }}, market);
    }

