    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        //     {
        //         "id": 170368702,
        //         "currency": "usdt",
        //         "chain": "Ethereum",
        //         "memo": "",
        //         "status": "SUCCESS",
        //         "amount": "31.792528",
        //         "confirmations": 12,
        //         "transactionId": "0x90b8487c258b81b85e15e461b1839c49d4d8e6e9de4c1adb658cd47d4f5c5321",
        //         "address": "0x7f7172cf29d3846d30ca5a3aec1120b92dbd150b",
        //         "fromAddr": "0x7830c87c02e56aff27fa9ab1241711331fa86f58",
        //         "createdTime": 1678491442000
        //     }
        //
        // fetchWithdrawals
        //
        //     {
        //         "id": 950898,
        //         "currency": "usdt",
        //         "chain": "Tron",
        //         "address": "TGB2vxTjiqraVZBy7YHXF8V3CSMVhQKcaf",
        //         "memo": "",
        //         "status": "SUCCESS",
        //         "amount": "5",
        //         "fee": "2",
        //         "confirmations": 6,
        //         "transactionId": "c36e230b879842b1d7afd19d15ee1a866e26eaa0626e367d6f545d2932a15156",
        //         "createdTime": 1680049062000
        //     }
        //
        // withdraw
        //
        //     {
        //         "id": 950898
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object type = ((Helpers.isTrue((Helpers.inOp(transaction, "fromAddr"))))) ? "deposit" : "withdraw";
        Object timestamp = this.safeInteger(transaction, "createdTime");
        Object address = this.safeString(transaction, "address");
        Object memo = this.safeString(transaction, "memo");
        Object currencyCode = this.safeCurrencyCode(this.safeString(transaction, "currency"), currency);
        Object fee = this.safeNumber(transaction, "fee");
        Object feeCurrency = ((Helpers.isTrue((!Helpers.isEqual(fee, null))))) ? currencyCode : null;
        Object networkId = this.safeString(transaction, "chain");
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", XtCore.this.safeString(transaction, "id") );
            put( "txid", XtCore.this.safeString(transaction, "transactionId") );
            put( "timestamp", timestamp );
            put( "datetime", XtCore.this.iso8601(timestamp) );
            put( "updated", null );
            put( "addressFrom", XtCore.this.safeString(transaction, "fromAddr") );
            put( "addressTo", address );
            put( "address", address );
            put( "tagFrom", null );
            put( "tagTo", null );
            put( "tag", memo );
            put( "type", type );
            put( "amount", XtCore.this.safeNumber(transaction, "amount") );
            put( "currency", currencyCode );
            put( "network", XtCore.this.networkIdToCode(networkId, currencyCode) );
            put( "status", XtCore.this.parseTransactionStatus(XtCore.this.safeString(transaction, "status")) );
            put( "comment", memo );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", feeCurrency );
                put( "cost", finalFee );
                put( "rate", null );
            }} );
            put( "internal", null );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "SUBMIT", "pending" );
            put( "REVIEW", "pending" );
            put( "AUDITED", "pending" );
            put( "PENDING", "pending" );
            put( "CANCEL", "canceled" );
            put( "FAIL", "failed" );
            put( "SUCCESS", "ok" );
        }};
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name xt#setLeverage
     * @description set the level of leverage for a market
     * @see https://doc.xt.com/#futures_useradjustLeverage
     * @param {float} leverage the rate of leverage
     * @param {string} symbol unified market symbol
     * @param {object} params extra parameters specific to the xt api endpoint
     * @param {string} params.positionSide 'LONG' or 'SHORT'
     * @returns {object} response from the exchange
     */
    public java.util.concurrent.CompletableFuture<Object> setLeverage(Object leverage2, Object... optionalArgs)
    {
        final Object leverage3 = leverage2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object leverage = leverage3;
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " setLeverage() requires a symbol argument")) ;
            }
            Object positionSide = this.safeString(parameters, "positionSide");
            this.checkRequiredArgument("setLeverage", positionSide, "positionSide", new java.util.ArrayList<Object>(java.util.Arrays.asList("LONG", "SHORT")));
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isLessThan(leverage, 1))) || Helpers.isTrue((Helpers.isGreaterThan(leverage, 125)))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " setLeverage() leverage should be between 1 and 125")) ;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            if (!Helpers.isTrue((Helpers.GetValue(market, "contract"))))
            {
                throw new BadSymbol((String)Helpers.add(this.id, " setLeverage() supports contract markets only")) ;
            }
            final Object finalLeverage = leverage;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "positionSide", positionSide );
                put( "leverage", finalLeverage );
            }};
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams("setLeverage", market, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(subType, "inverse")))
            {
                response = (this.privateInversePostFutureUserV1PositionAdjustLeverage(this.extend(request, parameters))).join();
            } else
            {
                response = (this.privateLinearPostFutureUserV1PositionAdjustLeverage(this.extend(request, parameters))).join();
            }
            //
            //     {
            //         "returnCode": 0,
            //         "msgInfo": "success",
            //         "error": null,
            //         "result": null
            //     }
            //
            return response;
        });

    }

