    public Object parseMarketLeverageTiers(Object info, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "rad_usdt",
        //         "leverageBrackets": [
        //             {
        //                 "symbol": "rad_usdt",
        //                 "bracket": 1,
        //                 "maxNominalValue": "5000",
        //                 "maintMarginRate": "0.025",
        //                 "startMarginRate": "0.05",
        //                 "maxStartMarginRate": null,
        //                 "maxLeverage": "20",
        //                 "minLeverage": "1"
        //             },
        //         ]
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object tiers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object brackets = this.safeValue(info, "leverageBrackets", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(brackets)); i++)
        {
            Object tier = Helpers.GetValue(brackets, i);
            Object marketId = this.safeString(info, "symbol");
            market = this.safeMarket(marketId, market, "_", "contract");
            Object minNotional = this.safeNumber(Helpers.GetValue(brackets, Helpers.subtract(i, 1)), "maxNominalValue", 0);
final Object finalMarket = market;
                        ((java.util.List<Object>)tiers).add(new java.util.HashMap<String, Object>() {{
                put( "tier", XtCore.this.safeInteger(tier, "bracket") );
                put( "symbol", XtCore.this.safeSymbol(marketId, finalMarket, "_", "contract") );
                put( "currency", Helpers.GetValue(finalMarket, "settle") );
                put( "minNotional", minNotional );
                put( "maxNotional", XtCore.this.safeNumber(tier, "maxNominalValue") );
                put( "maintenanceMarginRate", XtCore.this.safeNumber(tier, "maintMarginRate") );
                put( "maxLeverage", XtCore.this.safeNumber(tier, "maxLeverage") );
                put( "info", tier );
            }});
        }
        return tiers;
    }

